import React from 'react';
import { motion } from 'framer-motion';
import './Skills.css';

const Skills = () => {
  const skills = [
    {
      title: "AWS Services",
      description: "EC2, S3, RDS, Lambda, CloudFormation, VPC, IAM, CloudWatch, ECS, EKS, API Gateway, Route 53"
    },
    {
      title: "DevOps & Automation", 
      description: "Terraform, Ansible, Jenkins, GitLab CI/CD, Docker, Kubernetes, Infrastructure as Code"
    },
    {
      title: "Programming & Scripting",
      description: "Python, Bash, PowerShell, YAML, JSON, SQL"
    },
    {
      title: "Monitoring & Security",
      description: "CloudTrail, Config, GuardDuty, Security Hub, Prometheus, Grafana, ELK Stack"
    }
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2
      }
    }
  };

  const itemVariants = {
    hidden: { y: 20, opacity: 0 },
    visible: {
      y: 0,
      opacity: 1,
      transition: {
        duration: 0.6
      }
    }
  };

  return (
    <section id="skills" className="skills-section">
      <div className="container">
        <motion.h2 
          className="section-title"
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          Technical Skills
        </motion.h2>
        <motion.div 
          className="skills-grid"
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
        >
          {skills.map((skill, index) => (
            <motion.div 
              key={index}
              className="skill-card"
              variants={itemVariants}
              whileHover={{ 
                scale: 1.05,
                boxShadow: "0 10px 25px rgba(0,0,0,0.15)"
              }}
              transition={{ type: "spring", stiffness: 300 }}
            >
              <h3>{skill.title}</h3>
              <p>{skill.description}</p>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </section>
  );
};

export default Skills;
